{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표는 금요일 15:00 KST로 설정한다.",
        "condition": "smoke test가 통과해야 한다."
      },
      {
        "decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인한다.",
        "condition": "계약 자체가 잘못된 경우에만 스크립트를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "수요일에 릴리스한다.",
        "reason": "smoke test 통과가 선행되어야 한다."
      },
      {
        "proposal": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경한다.",
        "reason": "논의 후 거절되었다."
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 stretch goal로만 언급됨",
        "decision_status": "확정 아님"
      },
      {
        "goal": "README 설치 단계를 목요일까지 검토",
        "status": "가능하면 검토",
        "decision_status": "담당자 미정"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계 검토",
        "note": "필요성이 언급되었지만 owner가 지정되지 않았다."
      },
      {
        "item": "Hara의 tarball 경로 확인",
        "note": "Minjun의 smoke 결과 이후 확인만 언급되었고 정확한 기한은 없었다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로가 릴리스를 지연시킬 수 있다."
      },
      {
        "risk": "README 설치 단계가 오래되면 release notes가 사용자에게 잘못된 정보를 줄 수 있다."
      }
    ],
    "open_questions": [
      "최종 릴리스 승인 권한은 누구에게 있는가?",
      "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke test를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Doyun",
      "task": "failure triage note를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 smoke 결과를 게시한 뒤 generated tarball path를 확인한다.",
      "due": "미정",
      "status": "confirmed but undated",
      "source_certainty": "explicit"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Minjun의 smoke test 결과",
      "generated tarball path",
      "README install steps의 최신성",
      "최종 릴리스 승인 권한",
      "릴리스 노트에 내부 수요일 stretch goal을 넣을지 여부"
    ],
    "what_not_to_invent": [
      "customer 또는 외부 파트너 이름",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법적 승인 요건",
      "지정되지 않은 owner",
      "명시되지 않은 deadline"
    ]
  },
  "non_invention_rules": [
    "고객명 또는 외부 파트너명을 추정하지 않는다.",
    "예산, 보안, 장애, 법무 승인 관련 사실을 추가하지 않는다.",
    "owner가 없는 항목에 임의의 담당자를 배정하지 않는다.",
    "명시되지 않은 마감일을 만들어내지 않는다.",
    "회의 기록에 없는 최종 승인권자나 정책을 단정하지 않는다."
  ]
}
